/**
 * SlideTemplates.jsx
 * Template grafici per il Post Builder social.
 * Tutti usano inline style per compatibilità con html-to-image.
 *
 * Template disponibili:
 *  - TemplateCover    — cover evento 4:5 (1080×1350)
 *  - TemplateFoto     — foto pura 1:1 / 4:5 / 9:16
 *  - TemplateStoriaEvento — story 9:16 (1080×1920)
 *  - TemplateAgendaCover — teaser carosello agenda 4:5 (foto + copy, prima slide)
 *  - TemplateMenuEvento / TemplateMenuStoriaEvento — lista piatti da blocco menu
 */

// ─── Costanti brand ────────────────────────────────────────────────────────────
const BRAND_GOLD     = '#eece9d'
const DARK_BG        = '#13100a'
const BRAND_ADDRESS  = 'Via Europa 2 · Colle Brianza (LC)'

/** Sfondo foto: gradient sempre sotto; niente crossOrigin in preview (evita schermo nero se CORS fallisce).
 *  La cattura PNG usa già imgToDataUrl come fallback in SocialStudioPanel. */
function BgPhoto({ imageUrl, fallback }) {
  return (
    <>
      {fallback || (
        <div style={{
          position:   'absolute',
          inset:      0,
          background: 'linear-gradient(160deg, #2e1c08 0%, #1a0f06 45%, #080503 100%)',
        }} />
      )}
      {imageUrl ? (
        <img
          src={imageUrl}
          alt=""
          onError={e => { e.currentTarget.style.display = 'none' }}
          style={{
            position:  'absolute',
            inset:     0,
            width:     '100%',
            height:    '100%',
            objectFit: 'cover',
            display:   'block',
          }}
        />
      ) : null}
    </>
  )
}


// ─── Utility ──────────────────────────────────────────────────────────────────

function formatDataIT(dateStr) {
  if (!dateStr) return ''
  try {
    const raw = new Date(dateStr + 'T12:00:00').toLocaleDateString('it-IT', {
      weekday: 'short', day: 'numeric', month: 'long',
    })
    // "ven 1 maggio" → "Ven 1 Maggio"
    return raw.replace(/\b([a-z])/g, c => c.toUpperCase())
  } catch { return dateStr }
}

// ─── Logo block (logo + indirizzo opzionale) ──────────────────────────────────

function LogoBlock({ top = 72, logoW = 140, mostraIndirizzo = false, indirizzo = BRAND_ADDRESS }) {
  return (
    <div style={{
      position:       'absolute',
      top,
      left:           0,
      right:          0,
      display:        'flex',
      justifyContent: 'center',
      alignItems:     'center',
      gap:            28,
    }}>
      <img
        src={LOGO_URL}
        alt="Boogie Bistrot"
        style={{ width: logoW, display: 'block', flexShrink: 0 }}
      />
      {mostraIndirizzo && indirizzo && (
        <>
          <div style={{ width: 1, height: 36, background: 'rgba(238,206,157,0.35)', flexShrink: 0 }} />
          <div style={{
            fontSize:      22,
            lineHeight:    1.45,
            color:         'rgba(238,206,157,0.75)',
            fontFamily:    "'SofiaPro', 'Helvetica Neue', sans-serif",
            fontWeight:    400,
            letterSpacing: 0.3,
            whiteSpace:    'pre-line',
          }}>
            {indirizzo.replace(' · ', '\n')}
          </div>
        </>
      )}
    </div>
  )
}

// ─── Template Cover (4:5 — 1080×1350) ────────────────────────────────────────
