// ─── Template Prezzo Evento (4:5 — 1080×1350) ────────────────────────────────
// Mostra l'offerta/prezzo incluso in un evento: importo grande, voci incluse, data.

export function TemplatePrezzoEvento({
  titolo          = 'Titolo Evento',
  data            = '',
  dataTesto       = '',
  ora             = '',
  imageUrl        = '',
  prezzoImporto   = '26€',
  prezzoLabel     = 'Apericena',
  voci            = [],
  mostraIndirizzo = false,
  indirizzo       = BRAND_ADDRESS,
}) {
  const titleSize  = titolo.length > 22 ? 68 : titolo.length > 14 ? 82 : 96
  const prezzoSize = prezzoImporto.length > 5 ? 130 : prezzoImporto.length > 3 ? 158 : 188
  const dataPart   = dataTesto || (data ? formatDataIT(data) : '')
  const dataOra    = [dataPart, ora ? `ore ${ora}` : ''].filter(Boolean).join(' · ')

  return (
    <div
      style={{
        position:        'relative',
        width:           W_COVER,
        height:          H_COVER,
        backgroundColor: DARK_BG,
        overflow:        'hidden',
        fontFamily:      "'SofiaPro', 'Helvetica Neue', sans-serif",
      }}
    >
      {/* Foto di sfondo */}
      <BgPhoto imageUrl={imageUrl} fallback={<div style={{
          position:   'absolute',
          inset:      0,
          background: [
            'radial-gradient(ellipse at 25% 35%, rgba(200,130,40,0.3) 0%, transparent 45%)',
            'radial-gradient(ellipse at 75% 65%, rgba(140,70,15,0.25) 0%, transparent 42%)',
            'linear-gradient(160deg, #2e1c08 0%, #1a0f06 45%, #080503 100%)',
          ].join(', '),
        }} />} />

      {/* Overlay */}
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(12,6,0,0.74)' }} />

      <LogoBlock top={72} logoW={120} mostraIndirizzo={mostraIndirizzo} indirizzo={indirizzo} />

      {/* Zona contenuto: centrata verticalmente tra logo e fondo */}
      <div style={{
        position:       'absolute',
        top:            210,
        left:           72,
        right:          72,
        bottom:         110,
        display:        'flex',
        flexDirection:  'column',
        alignItems:     'center',
        justifyContent: 'center',
      }}>

        {/* Titolo (prezzoLabel come heading principale) */}
        {prezzoLabel && (
          <div style={{
            fontFamily:   "'Alga', 'Georgia', serif",
            fontSize:      titleSize,
            fontWeight:   600,
            lineHeight:   0.95,
            color:        BRAND_GOLD,
            textAlign:    'left',
            wordBreak:    'break-word',
            width:        '100%',
            marginBottom: 48,
          }}>
            {prezzoLabel}
          </div>
        )}

        {/* Separatore */}
        <div style={{ width: '100%', height: 1, background: 'rgba(238,206,157,0.25)', marginBottom: 44 }} />

        {/* Voci incluse */}
        {voci.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 18, width: '100%', marginBottom: 44 }}>
            <div style={{
              fontSize:      24,
              fontWeight:    600,
              letterSpacing: 5,
              textTransform: 'uppercase',
              color:         BRAND_GOLD,
              marginBottom:  10,
            }}>
              Cosa è incluso
            </div>
            {voci.map((v, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 22, fontSize: 34, lineHeight: 1.35 }}>
                <span style={{ color: BRAND_GOLD, fontWeight: 700, flexShrink: 0, marginTop: 1 }}>✓</span>
                <span style={{ color: 'rgba(255,255,255,0.88)' }}>{v}</span>
              </div>
            ))}
          </div>
        )}

        {/* Separatore */}
        <div style={{ width: '100%', height: 1, background: 'rgba(238,206,157,0.25)', marginBottom: 36 }} />

        {/* Importo — allineato a destra */}
        <div style={{
          fontFamily:    "'Alga', 'Georgia', serif",
          fontSize:      prezzoSize * 0.58,
          fontWeight:    600,
          lineHeight:    1,
          color:         BRAND_GOLD,
          letterSpacing: -0.5,
          textAlign:     'right',
          width:         '100%',
        }}>
          {prezzoImporto}
        </div>

      </div>

      {/* Data + ora — pill in basso */}
      {dataOra && (
        <div style={{ position: 'absolute', bottom: 60, left: 0, right: 0, display: 'flex', justifyContent: 'center' }}>
          <div style={{
            display:       'inline-block',
            padding:       '10px 34px',
            border:        `1.5px solid rgba(238,206,157,0.4)`,
            borderRadius:  999,
            fontSize:      30,
            fontWeight:    400,
            color:         BRAND_GOLD,
            letterSpacing: 0.4,
            whiteSpace:    'nowrap',
          }}>
            {dataOra}
          </div>
        </div>
      )}
    </div>
  )
}

// ─── Template Storia Evento (9:16 — 1080×1920) ───────────────────────────────

const W_STORIA = 1080
const H_STORIA = 1920

export function TemplateStoriaEvento({ titolo = 'Titolo Evento', data = '', dataTesto = '', ora = '', imageUrl = '', mostraIndirizzo = false, indirizzo = BRAND_ADDRESS, stasera = false }) {
  const titoloFontSize = titolo.length > 25 ? 88 : titolo.length > 15 ? 110 : 130

  return (
    <div
      style={{
        position:        'relative',
        width:           W_STORIA,
        height:          H_STORIA,
        backgroundColor: DARK_BG,
        overflow:        'hidden',
        fontFamily:      "'SofiaPro', 'Helvetica Neue', sans-serif",
      }}
    >
      <BgPhoto imageUrl={imageUrl} />

      {/* Gradient overlay */}
      <div style={{
        position:   'absolute',
        inset:      0,
        background: 'linear-gradient(to top, rgba(18,12,3,0.95) 0%, rgba(18,12,3,0.55) 40%, rgba(18,12,3,0.15) 100%)',
      }} />

      <LogoBlock top={110} logoW={130} mostraIndirizzo={mostraIndirizzo} indirizzo={indirizzo} />

      {/* Contenuto in basso */}
      <div style={{ position: 'absolute', bottom: 220, left: 90, right: 90 }}>

        {/* Badge — "STASERA" riempito (modalità stasera) oppure "EVENTO" outline */}
        {stasera ? (
          <div style={{
            display:         'inline-block',
            padding:         '18px 56px',
            backgroundColor: BRAND_GOLD,
            borderRadius:    999,
            fontSize:        42,
            fontWeight:      700,
            letterSpacing:   8,
            textTransform:   'uppercase',
            color:           DARK_BG,
            marginBottom:    52,
          }}>
            Stasera
          </div>
        ) : (
          <div style={{
            display:       'inline-block',
            padding:       '8px 26px',
            border:        `1px solid ${BRAND_GOLD}`,
            borderRadius:  999,
            fontSize:       22,
            fontWeight:    600,
            letterSpacing: 5,
            textTransform: 'uppercase',
            color:         BRAND_GOLD,
            marginBottom:  44,
          }}>
            Evento
          </div>
        )}

        {/* Titolo */}
        <div style={{
          fontFamily:   "'Alga', 'Georgia', serif",
          fontSize:      titoloFontSize,
          fontWeight:   600,
          lineHeight:   1.05,
          color:        '#ffffff',
          marginBottom: 44,
        }}>
          {titolo}
        </div>

        {/* Data e ora — in modalità stasera mostra solo l'ora */}
        {stasera ? (
          ora && (
            <div style={{
              fontSize:      36,
              fontWeight:    600,
              color:         BRAND_GOLD,
              letterSpacing: 2,
            }}>
              ore {ora}
            </div>
          )
        ) : (
          (dataTesto || data || ora) && (
            <div style={{
              fontSize:      28,
              fontWeight:    500,
              color:         BRAND_GOLD,
              letterSpacing: 2,
              textTransform: dataTesto ? 'none' : 'capitalize',
            }}>
              {dataTesto ? `${dataTesto}${ora ? ` — ${ora}` : ''}` : `${formatDataIT(data)}${ora ? ` — ${ora}` : ''}`}
            </div>
          )
        )}
      </div>

      {/* CTA prenota */}
      <div style={{
        position:       'absolute',
        bottom:         80,
        left:           0,
        right:          0,
        textAlign:      'center',
        fontFamily:     "'SofiaPro', sans-serif",
        fontSize:       28,
        fontWeight:     400,
        letterSpacing:  1,
        color:          'rgba(255,255,255,0.7)',
      }}>
        ↑ prenota nel link in bio
      </div>

      {/* Linea brand */}
      <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 6, backgroundColor: BRAND_GOLD }} />
    </div>
  )
}

