function formatAgendaData(dateStr) {
  if (!dateStr) return ''
  try {
    return new Date(dateStr + 'T12:00:00').toLocaleDateString('it-IT', { weekday: 'long', day: 'numeric', month: 'long' })
      .replace(/\b([a-z])/g, c => c.toUpperCase())
  } catch { return dateStr }
}

