// ─── Componente generico che sceglie il template giusto ────────────────────────

export function SlideRenderer({ slide, style }) {
  const { template, data: d = {} } = slide
  const T = TEMPLATES[template]
  if (!T) return null
  const { Component } = T
  return <Component {...d} style={style} />
}
